  1→import { useEffect, useMemo, useState } from "react";
  2→import { MoonLoader } from "react-spinners";
  3→import { useInfiniteQuery } from "@tanstack/react-query";
  4→import { useNavigate } from "react-router-dom";
  5→import { useInView } from "react-intersection-observer";
  6→import { getCanvasGallery } from "../../../../API/Api";
  7→import { useAuth } from "../../../Context/useAuth";
  8→import formatPostDate from "../../../../helpers/formatDateString";
  9→import { handleClickProfile } from "../../../../helpers/handleClicks";
 10→import VerifiedBadge from "../../Badge/VerifiedBadge";
 11→import { getCanvasPreview } from "../../../utils/canvasDoc";
 12→import CanvasPreview from "../postCards/CanvasPreview/CanvasPreview";
 13→import CalculateText from "../postCards/calculateReadingTime";
 14→import "./gallery.css";
 15→
 16→const CANVAS_GALLERY_PAGE_SIZE = 5;
 17→
 18→const GalleryPage = () => {
 19→    const navigate = useNavigate();
 20→    const {session, user, openAuthModal} = useAuth();
 21→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
 22→    const userId = user?.userData?.[0]?.id || null;
 23→    const [sortMode, setSortMode] = useState('hottest');
 24→    const {ref: inViewRef, inView} = useInView({threshold: 0.1});
 25→
 26→    const {
 27→        data,
 28→        isLoading,
 29→        isFetching,
 30→        isFetchingNextPage,
 31→        fetchNextPage,
 32→        hasNextPage
 33→    } = useInfiniteQuery({
 34→        queryKey: ['canvasGallery', userId, sortMode],
 35→        queryFn: ({pageParam = null}) => getCanvasGallery(userId, CANVAS_GALLERY_PAGE_SIZE, sortMode, pageParam),
 36→        initialPageParam: null,
 37→        getNextPageParam: (lastPage) => (lastPage?.hasMore ? lastPage?.nextCursor : undefined),
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 45
 40→    });
 41→
 42→    useEffect(() => {
 43→        if(inView && hasNextPage && !isFetchingNextPage){
 44→            fetchNextPage();
 45→        }
 46→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
 47→
 48→    const journals = useMemo(() => (
 49→        (data?.pages || [])
 50→            .flatMap((page) => page?.data || [])
 51→            .filter((journal) => journal?.post_type === "canvas")
 52→    ), [data?.pages]);
 53→
 54→    const handleOpenCanvas = (journalId) => {
 55→        if(!session){
 56→            openAuthModal();
 57→            return;
 58→        }
 59→        navigate(`/home/post/${journalId}`);
 60→    };
 61→
 62→    const handleClickUserProfile = (event, clickedUserId) => {
 63→        event.stopPropagation();
 64→        if(!session){
 65→            openAuthModal();
 66→            return;
 67→        }
 68→        handleClickUserProfileOriginal(event, userId, clickedUserId);
 69→    };
 70→
 71→    const handleRemixCanvas = (event, journal) => {
 72→        event.stopPropagation();
 73→        if(!session){
 74→            openAuthModal();
 75→            return;
 76→        }
 77→
 78→        const sourceTitle = typeof journal?.title === 'string' ? journal.title.trim() : '';
 79→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
 80→            ? sourceTitle
 81→            : `Remix: ${sourceTitle || 'Canvas'}`;
 82→
 83→        navigate('/home', {
 84→            state: {
 85→                openEditor: true,
 86→                editorMode: 'canvas',
 87→                initialTitle: remixTitle,
 88→                initialCanvasDoc: journal?.canvas_doc || null,
 89→                remixSource: {
 90→                    journalId: journal?.id,
 91→                    authorName: journal?.users?.name || 'Unknown'
 92→                }
 93→            }
 94→        });
 95→    };
 96→
 97→    if(isLoading){
 98→        return (
 99→            <div className="gallery-loading-state">
100→                <MoonLoader loading={isLoading} color="var(--loader-color)" size={20} />
101→            </div>
102→        );
103→    }
104→
105→    return (
106→        <div className="gallery-page-root">
107→            <div className="gallery-top-bar">
108→                <div className="gallery-title-shell">
109→                    <h2 className="gallery-title">Gallery</h2>
110→                    <p className="gallery-subtitle">Canvas posts arranged as visual pieces</p>
111→                </div>
112→
113→                <div className="gallery-sort-shell">
114→                    <button
115→                        type="button"
116→                        className={`gallery-sort-btn ${sortMode === 'hottest' ? 'is-active' : ''}`}
117→                        onClick={() => setSortMode('hottest')}
118→                    >
119→                        Hottest
120→                    </button>
121→                    <button
122→                        type="button"
123→                        className={`gallery-sort-btn ${sortMode === 'newest' ? 'is-active' : ''}`}
124→                        onClick={() => setSortMode('newest')}
125→                    >
126→                        Newest
127→                    </button>
128→                </div>
129→            </div>
130→
131→            {isFetching && !isFetchingNextPage && (
132→                <div className="gallery-refresh-pill">Refreshing...</div>
133→            )}
134→
135→            {journals.length === 0 ? (
136→                <div className="gallery-empty-state">No public canvases yet.</div>
137→            ) : (
138→                <>
139→                    <div className="gallery-cards">
140→                        {journals.map((journal) => {
141→                            const canvasPreview = getCanvasPreview(journal?.canvas_doc);
142→                            const previewText = canvasPreview?.slicedText || 'No text added to this canvas yet.';
143→                            const wholeText = canvasPreview?.wholeText || '';
144→
145→                            return (
146→                            <article
147→                                key={journal.id}
148→                                className="gallery-canvas-card"
149→                                onClick={() => handleOpenCanvas(journal.id)}
150→                                role="button"
151→                                tabIndex={0}
152→                                onKeyDown={(event) => {
153→                                    if(event.key === 'Enter' || event.key === ' '){
154→                                        event.preventDefault();
155→                                        handleOpenCanvas(journal.id);
156→                                    }
157→                                }}
158→                            >
159→                                <CanvasPreview canvasDoc={journal?.canvas_doc} />
160→                                <div className="gallery-canvas-content">
161→                                    <div className="gallery-content-container">
162→                                        <div className="gallery-feed-text-content-container">
163→                                            <div className="gallery-feed-title-content">
164→                                                <span className="gallery-canvas-type-badge">
165→                                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor"
166→                                                         strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
167→                                                        <path d="M12 19l7-7 3 3-7 7-3-3z"/>
168→                                                        <path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"/>
169→                                                        <path d="M2 2l7.586 7.586"/>
170→                                                        <circle cx="11" cy="11" r="2"/>
171→                                                    </svg>
172→                                                    Canvas
173→                                                </span>
174→                                                <h3 className="gallery-feed-title">
175→                                                    {journal?.title?.length > 55 ? `${journal.title.substring(0, 55)}...` : (journal?.title || 'Untitled Canvas')}
176→                                                </h3>
177→                                            </div>
178→                                            <p className="gallery-feed-text-content">
179→                                                {previewText}
180→                                            </p>
181→                                        </div>
182→                                    </div>
183→
184→                                    <div className="gallery-canvas-actions">
185→                                        <button
186→                                            type="button"
187→                                            className="gallery-canvas-action-btn is-remix"
188→                                            onClick={(event) => handleRemixCanvas(event, journal)}
189→                                        >
190→                                            Remix this Canvas
191→                                        </button>
192→                                    </div>
193→                                </div>
194→
195→                                <div className="gallery-card-footer">
196→                                    <div
197→                                        className="gallery-user-info-child-container"
198→                                        onClick={(event) => handleClickUserProfile(event, journal?.users?.id)}
199→                                    >
200→                                        <div className={`gallery-user-avatar-container ${journal?.users?.badge === 'legend' ? 'avatar-ring-legend' : journal?.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
201→                                            <img
202→                                                loading="lazy"
203→                                                className="gallery-user-info-avatar"
204→                                                src={journal?.users?.image_url || '/assets/profile.jpg'}
205→                                                alt={`${journal?.users?.name || "User"} profile picture`}
206→                                            />
207→                                        </div>
208→                                        <div className="gallery-user-name-container">
209→                                            <p className="gallery-user-newsfeed-name">{journal?.users?.name || 'Unknown'}</p>
210→                                            <VerifiedBadge badge={journal?.users?.badge} size={14} />
211→                                        </div>
212→                                        <div className="gallery-name-info-separator">•</div>
213→                                        <p className="gallery-user-post-date">{formatPostDate(journal?.created_at)}</p>
214→                                    </div>
215→
216→                                    <div className="gallery-reading-time-container">
217→                                        <p className="gallery-reading-time-text">{CalculateText(wholeText)}</p>
218→                                    </div>
219→
220→                                    <div className="gallery-card-score">
221→                                        <span>Hot score</span>
222→                                        <span>{journal?.hot_score || 0}</span>
223→                                    </div>
224→                                </div>
225→                            </article>
226→                        )})}
227→                    </div>
228→
229→                    {isFetchingNextPage && (
230→                        <div className="gallery-next-loading">
231→                            <MoonLoader loading={isFetchingNextPage} color="var(--loader-color)" size={16} />
232→                        </div>
233→                    )}
234→
235→                    {hasNextPage && <div ref={inViewRef} className="gallery-infinite-sentinel" />}
236→                </>
237→            )}
238→        </div>
239→    );
240→}
241→
242→export default GalleryPage;
