 61→    const bookmarkInFlightRef = useRef(false);
 62→
 63→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 64→    const [isLiked, setIsliked] = useState(false);
 65→    const [likesCount, setLikesCount] = useState(0);
 66→    const [isBookmarked, setIsBookmarked] = useState(false);
 67→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 68→
 69→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 70→
 71→    const contentRef = useRef();
 72→
 73→    const theme = {
 74→        paragraph: 'editor-paragraph',
