228→
229→    }
230→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
231→
232→    const mutationFollow = useFollowMutation(session);
233→    const handleClickFollow = async (e, followingId, followerId) => {
234→        e.stopPropagation();
